#!/usr/bin/env pwsh\n\n# 🧪 MiPuesto Deployment Verification Script\n# Este script verifica que tu deployment está 100% funcional\n\nparam(\n    [string]$RenderUrl = \"\",\n    [string]$VercelUrl = \"\",\n    [string]$DatabaseUrl = \"\"\n)\n\nif (-not $RenderUrl) {\n    $RenderUrl = Read-Host \"Enter your Render API URL (e.g., https://mipuesto-api.onrender.com)\"\n}\nif (-not $VercelUrl) {\n    $VercelUrl = Read-Host \"Enter your Vercel Frontend URL (e.g., https://mipuesto.vercel.app)\"\n}\n\n$GREEN = \"`e[32m\"\n$RED = \"`e[31m\"\n$YELLOW = \"`e[33m\"\n$BLUE = \"`e[34m\"\n$RESET = \"`e[0m\"\n\nWrite-Host \"\"\nWrite-Host \"${BLUE}=== MiPuesto Deployment Verification ===${RESET}\"\nWrite-Host \"\"\n\n$results = @()\n\n# Test 1: API Health Check\nWrite-Host \"Test 1: ${YELLOW}API Health Check${RESET}\"\ntry {\n    $response = Invoke-WebRequest -Uri \"$RenderUrl/api/health\" -Method Get -ErrorAction Stop\n    if ($response.StatusCode -eq 200) {\n        Write-Host \"${GREEN}✅ API is responding${RESET}\"\n        $results += \"✅ API Health\"\n    }\n} catch {\n    Write-Host \"${RED}❌ API health check failed${RESET}\"\n    Write-Host \"   Error: $($_.Exception.Message)\"\n    $results += \"❌ API Health\"\n}\nWrite-Host \"\"\n\n# Test 2: Database Connection\nWrite-Host \"Test 2: ${YELLOW}Database Connection${RESET}\"\ntry {\n    $response = Invoke-WebRequest -Uri \"$RenderUrl/api/subscriptions/plans\" -Method Get -ErrorAction Stop\n    if ($response.StatusCode -eq 200 -and $response.Content -match 'INTERMEDIO') {\n        Write-Host \"${GREEN}✅ Database is connected${RESET}\"\n        $results += \"✅ Database\"\n    }\n} catch {\n    Write-Host \"${RED}❌ Database connection failed${RESET}\"\n    Write-Host \"   Error: $($_.Exception.Message)\"\n    $results += \"❌ Database\"\n}\nWrite-Host \"\"\n\n# Test 3: Frontend Load\nWrite-Host \"Test 3: ${YELLOW}Frontend Loads${RESET}\"\ntry {\n    $response = Invoke-WebRequest -Uri $VercelUrl -Method Get -ErrorAction Stop\n    if ($response.StatusCode -eq 200) {\n        Write-Host \"${GREEN}✅ Frontend is loading${RESET}\"\n        $results += \"✅ Frontend\"\n    }\n} catch {\n    Write-Host \"${RED}❌ Frontend load failed${RESET}\"\n    Write-Host \"   Error: $($_.Exception.Message)\"\n    $results += \"❌ Frontend\"\n}\nWrite-Host \"\"\n\n# Test 4: CORS Configuration\nWrite-Host \"Test 4: ${YELLOW}CORS Configuration${RESET}\"\ntry {\n    $headers = @{\n        \"Origin\" = $VercelUrl\n        \"Access-Control-Request-Method\" = \"GET\"\n    }\n    $response = Invoke-WebRequest -Uri \"$RenderUrl/api/health\" -Method Get -Headers $headers -ErrorAction Stop\n    Write-Host \"${GREEN}✅ CORS is configured${RESET}\"\n    $results += \"✅ CORS\"\n} catch {\n    Write-Host \"${YELLOW}⚠️  CORS check inconclusive (may still work)${RESET}\"\n    $results += \"⚠️  CORS\"\n}\nWrite-Host \"\"\n\n# Summary\nWrite-Host \"${BLUE}=== SUMMARY ===${RESET}\"\nforeach ($result in $results) {\n    Write-Host $result\n}\nWrite-Host \"\"\n\nif ($results.Count -ge 3) {\n    Write-Host \"${GREEN}✅ Your MiPuesto deployment is WORKING!${RESET}\"\n    Write-Host \"\"\n    Write-Host \"URLs:\"\n    Write-Host \"  Frontend:  $VercelUrl\"\n    Write-Host \"  Backend:   $RenderUrl\"\n    Write-Host \"  Database:  Supabase\"\n} else {\n    Write-Host \"${RED}⚠️  Some tests failed. Check the errors above.${RESET}\"\n}\n\nWrite-Host \"\"\n